#define WIDTH 16
#define HEIGHT 16
#define BLOCK_SIZE 16

float squash(float x) {
    return 1.0f / (1.0f + exp(-x));
}

kernel void bpnn_layerforward_ocl(global float* l1,
                                  global float* l2,
                                  global float* conn_flat,
                                  global float* partial_sum,
                                  local float* local_conn,
                                  local float* local_l1,
                                  int n1,
                                  int n2) {
    int j = get_global_id(1);
    int block_idx = get_global_id(0) / BLOCK_SIZE;
    int local_idx = get_global_id(0) % BLOCK_SIZE;

    if (j >= 1 && j <= n2) {
        float sum = 0.0f;

        for (int k_block = 0; k_block < (n1 + 1); k_block += BLOCK_SIZE) {
            int k = k_block + local_idx;

            if (k <= n1) {
                local_l1[local_idx] = l1[k];
                for (int r = 0; r < WIDTH; r++) {
                    if (j <= n2 && (k_block + r) <= n1) {
                        local_conn[local_idx * WIDTH + r] = conn_flat[(k_block + r) * (n2 + 1) + j];
                    }
                }
            }

            barrier(CLK_LOCAL_MEM_FENCE);

            if (k <= n1) {
                float l1_val = local_l1[local_idx];
                for (int r = 0; r < WIDTH; r++) {
                    int col_idx = k_block + r;
                    if (col_idx <= n1) {
                        sum += local_conn[local_idx * WIDTH + r] * l1_val;
                    }
                }
            }

            barrier(CLK_LOCAL_MEM_FENCE);
        }

        partial_sum[block_idx * n2 + (j - 1)] = sum;
    }
}

kernel void bpnn_adjust_weights_ocl(global float* delta,
                                    int ndelta,
                                    global float* ly,
                                    int nly,
                                    global float* w_flat,
                                    global float* oldw_flat) {
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j >= 1 && j <= ndelta && k <= nly) {
        float new_dw = (0.3f * delta[j] * ly[k]) + (0.3f * oldw_flat[k * (ndelta + 1) + j]);
        w_flat[k * (ndelta + 1) + j] += new_dw;
        oldw_flat[k * (ndelta + 1) + j] = new_dw;
    }
}
